import React, { memo, useCallback } from "react";
import styles from "./BoardHeader.module.css";

export interface BoardHeaderProps {
  title: string;
}

export const BoardHeader: React.FC<BoardHeaderProps> = memo(({ title }) => {
  const handleRefreshClick = useCallback(() => {
    console.log("Board refreshed");
  }, []);

  return (
    <header className={styles.header}>
      <h1 className={styles.title}>{title}</h1>
      <button
        type="button"
        className={styles.refreshButton}
        onClick={handleRefreshClick}
        aria-label="Refresh board"
        title="Refresh board"
      >
        <svg
          className={styles.refreshIcon}
          xmlns="http://www.w3.org/2000/svg"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          strokeWidth="2"
          strokeLinecap="round"
          strokeLinejoin="round"
          aria-hidden="true"
        >
          <polyline points="23 4 23 10 17 10" />
          <path d="M20.49 15a9 9 0 1 1-2.12-9.36L23 10" />
        </svg>
        <span className={styles.refreshLabel}>Refresh</span>
      </button>
    </header>
  );
});

BoardHeader.displayName = "BoardHeader";

.header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  padding: 0.75rem 1rem;
  border-bottom: 1px solid var(--color-border, #e2e8f0);
  background-color: var(--color-surface, #ffffff);
}

.title {
  margin: 0;
  font-size: 1.25rem;
  font-weight: 600;
  color: var(--color-text-primary, #1e293b);
  line-height: 1.2;
}

.refreshButton {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  padding: 0.375rem 0.625rem;
  font-size: 0.875rem;
  font-weight: 500;
  color: var(--color-text-secondary, #475569);
  background-color: var(--color-surface, #ffffff);
  border: 1px solid var(--color-border, #cbd5e1);
  border-radius: 0.375rem;
  cursor: pointer;
  transition: background-color 150ms ease, border-color 150ms ease, color 150ms ease;
}

.refreshButton:hover {
  background-color: var(--color-surface-hover, #f1f5f9);
  border-color: var(--color-border-hover, #94a3b8);
  color: var(--color-text-primary, #1e293b);
}

.refreshButton:focus-visible {
  outline: 2px solid var(--color-focus-ring, #3b82f6);
  outline-offset: 2px;
}

.refreshIcon {
  width: 1rem;
  height: 1rem;
  flex-shrink: 0;
}

.refreshLabel {
  line-height: 1;
}
